import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function TaskDetail() {
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [task, setTask] = useState(null);
  const [responses, setResponses] = useState([]);
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const fetchTask = async () => {
    try {
      const res = await api.get(`/tasks/${id}`);
      setTask(res.data);
      if (res.data.customer_id === user?.id && res.data.status === 'open') {
        const rRes = await api.get(`/tasks/${id}/responses`);
        setResponses(rRes.data);
      }
    } catch {
      setError('Задача не найдена');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchTask(); }, [id]);

  const handleRespond = async () => {
    if (!user) return navigate('/signin');
    setActionLoading(true);
    try {
      await api.post(`/tasks/${id}/respond`, { message });
      setSuccess('Вы откликнулись на задачу!');
      setMessage('');
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка');
    } finally {
      setActionLoading(false);
    }
  };

  const handleSelectHelper = async (helperId) => {
    setActionLoading(true);
    try {
      await api.post(`/tasks/${id}/select-helper`, { helper_id: helperId });
      navigate(`/tasks/${id}/status`);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка');
    } finally {
      setActionLoading(false);
    }
  };

  if (loading) return (
    <div className="app-container">
      <div className="loading"><div className="spinner" /></div>
    </div>
  );

  if (!task) return (
    <div className="app-container" style={{ padding: 20 }}>
      <div className="error-msg">{error || 'Задача не найдена'}</div>
    </div>
  );

  const isOwner = user?.id === task.customer_id;
  const isHelper = user?.id === task.helper_id;
  const canRespond = user && !isOwner && task.status === 'open';

  return (
    <div className="app-container">
      <div className="page-header">
        <button className="back-btn" onClick={() => navigate(-1)}>← Назад</button>
        <span className="page-title">Task Details</span>
      </div>

      <div style={{ padding: '20px 20px 40px' }}>
        {error && <div className="error-msg">{error}</div>}
        {success && (
          <div style={{ background: '#dcfce7', color: '#16a34a', padding: 12, borderRadius: 10, marginBottom: 16, textAlign: 'center', fontWeight: 600 }}>
            {success}
          </div>
        )}

        {/* Task card */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
            <h2 style={{ fontSize: 20, fontWeight: 800, flex: 1 }}>{task.title}</h2>
            <span className={`badge badge-${task.status}`} style={{ marginLeft: 8, whiteSpace: 'nowrap' }}>
              {task.status === 'open' ? 'Открыта' : task.status === 'in_progress' ? 'В работе' : 'Завершена'}
            </span>
          </div>

          {task.description && (
            <p style={{ color: 'var(--text-muted)', fontSize: 15, lineHeight: 1.5, marginBottom: 12 }}>
              {task.description}
            </p>
          )}

          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {task.payment && (
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span>💰</span>
                <span style={{ fontWeight: 700, color: 'var(--green)' }}>{task.payment} ₸</span>
              </div>
            )}
            {task.location_name && (
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, color: 'var(--text-muted)', fontSize: 14 }}>
                <span>📍</span><span>{task.location_name}</span>
              </div>
            )}
            {task.category && (
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, color: 'var(--text-muted)', fontSize: 14 }}>
                <span>🏷️</span><span>{task.category}</span>
              </div>
            )}
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, color: 'var(--text-muted)', fontSize: 13 }}>
              <span>🕐</span>
              <span>
                {task.created_at
                  ? new Date(task.created_at).toLocaleString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })
                  : 'Сегодня'}
              </span>
            </div>
          </div>
        </div>

        {/* Customer info */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600, marginBottom: 8, textTransform: 'uppercase' }}>
            Заказчик
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              width: 44, height: 44, borderRadius: '50%', background: 'var(--green-pale)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 18, fontWeight: 700, color: 'var(--green)'
            }}>
              {task.customer_name?.[0]?.toUpperCase()}
            </div>
            <div>
              <div style={{ fontWeight: 700 }}>{task.customer_name}</div>
              <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>⭐ {task.customer_rating || '—'}</div>
            </div>
          </div>
        </div>

        {/* Helper response form */}
        {canRespond && (
          <div className="card" style={{ marginBottom: 16 }}>
            <div style={{ fontWeight: 700, marginBottom: 12 }}>Откликнуться на задачу</div>
            <textarea
              style={{
                width: '100%', background: '#f1f5f0', border: '1.5px solid transparent',
                borderRadius: 10, padding: 12, fontSize: 15, resize: 'vertical',
                outline: 'none', fontFamily: 'inherit', marginBottom: 12
              }}
              rows={3}
              placeholder="Напишите сообщение заказчику..."
              value={message}
              onChange={e => setMessage(e.target.value)}
            />
            <button className="btn-primary" onClick={handleRespond} disabled={actionLoading}>
              {actionLoading ? 'Отправляем...' : 'Offer to help'}
            </button>
          </div>
        )}

        {/* Owner: choose helper */}
        {isOwner && task.status === 'open' && responses.length > 0 && (
          <div>
            <h3 style={{ fontWeight: 700, fontSize: 16, marginBottom: 12 }}>
              Откликнулись ({responses.length})
            </h3>
            {responses.map(resp => (
              <div key={resp.id} className="card" style={{ marginBottom: 10 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 10 }}>
                  <div style={{
                    width: 44, height: 44, borderRadius: '50%', background: '#e5e7eb',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 18, fontWeight: 700
                  }}>
                    {resp.username?.[0]?.toUpperCase()}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 700 }}>{resp.username}</div>
                    <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>
                      ⭐ {resp.rating || '—'} · {resp.rating_count || 0} отзывов
                    </div>
                  </div>
                  <button
                    className="btn-primary"
                    style={{ width: 'auto', padding: '8px 16px', fontSize: 14 }}
                    onClick={() => handleSelectHelper(resp.helper_id)}
                    disabled={actionLoading}
                  >
                    Choose
                  </button>
                </div>
                {resp.message && (
                  <p style={{ fontSize: 14, color: 'var(--text-muted)', padding: '8px 0', borderTop: '1px solid var(--border)' }}>
                    "{resp.message}"
                  </p>
                )}
              </div>
            ))}
          </div>
        )}

        {isOwner && task.status === 'open' && responses.length === 0 && (
          <div style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '20px 0', fontSize: 14 }}>
            Пока нет откликов на вашу задачу
          </div>
        )}

        {/* Task in progress */}
        {(isOwner || isHelper) && task.status === 'in_progress' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            <button className="btn-primary" onClick={() => navigate(`/tasks/${id}/status`)}>
              Task Status
            </button>
            <button className="btn-secondary" onClick={() => navigate(`/chat/${id}`)}>
              💬 Message
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
